```typescript
// Pipeline Status
export type PipelineStatus = 'running' | 'idle' | 'queued' | 'failed';

export interface Pipeline {
  id: string;
  name: string;
  icon: string; // Unicode or emoji
  color: 'purple' | 'cyan' | 'pink' | 'teal';
  status: PipelineStatus;
  progress?: number; // 0-100
  currentJob?: string;
  nextRun?: Date;
  lastError?: string;
  successRate?: number;
}

// Job Status
export type JobStatus = 'queued' | 'running' | 'completed' | 'failed' | 'cancelled';

export interface Job {
  id: string;
  pipelineId: string;
  status: JobStatus;
  createdAt: Date;
  startedAt?: Date;
  completedAt?: Date;
  progress?: number;
  error?: string;
  logs?: string[];
  metadata?: Record<string, any>;
}

// Activity Feed
export type ActivityType = 'started' | 'completed' | 'failed' | 'queued' | 'progress';

export interface ActivityItem {
  id: string;
  type: ActivityType;
  pipelineId: string;
  pipelineName: string;
  message: string;
  timestamp: Date;
  details?: Record<string, any>;
  actionable?: {
    label: string;
    action: () => void;
  }[];
}

// System Status
export type SystemHealth = 'healthy' | 'degraded' | 'error';

export interface SystemStatus {
  health: SystemHealth;
  activeJobs: number;
  queuedJobs: number;
  totalCapacity: number;
  websocketConnected: boolean;
  lastUpdate: Date;
}
```

