/**
 * Doppler + Sentry Setup Helper
 * Adds Sentry DSN to Doppler and updates local .env
 */

import { exec } from 'child_process';
import { promisify } from 'util';
import readline from 'readline';
import fs from 'fs/promises';

const execAsync = promisify(exec);

const PROJECT = 'integrity-studio';
const CONFIG = 'dev';

function question(rl, prompt) {
  return new Promise((resolve) => {
    rl.question(prompt, resolve);
  });
}

async function checkDopplerInstalled() {
  try {
    await execAsync('doppler --version');
    console.log('✅ Doppler CLI detected\n');
  } catch {
    console.error('❌ Doppler CLI not found. Please install it first:');
    console.error('   brew install dopplerhq/cli/doppler');
    console.error('   or visit: https://docs.doppler.com/docs/install-cli');
    process.exit(1);
  }
}

async function checkDopplerAuthenticated() {
  try {
    await execAsync('doppler configure get token.current');
    console.log('✅ Doppler authenticated\n');
  } catch {
    console.error('❌ Not logged in to Doppler. Please run:');
    console.error('   doppler login');
    process.exit(1);
  }
}

function printDsnInstructions() {
  console.log('Step 1: Get Your Sentry DSN');
  console.log('═══════════════════════════');
  console.log('Your Sentry DSN should look like:');
  console.log('https://abc123def456@o123456.ingest.sentry.io/7890123');
  console.log();
  console.log('To get your DSN:');
  console.log('1. Go to https://sentry.io/');
  console.log('2. Select your project (or create one: Node.js)');
  console.log('3. Settings → Client Keys (DSN)');
  console.log('4. Copy the DSN');
  console.log();
}

async function promptAndValidateDsn(rl) {
  const dsn = await question(rl, 'Enter your Sentry DSN: ');
  if (!dsn || !dsn.includes('sentry.io')) {
    console.error('\n❌ Invalid DSN format');
    rl.close();
    process.exit(1);
  }
  return dsn;
}

async function addDsnToDoppler(dsn) {
  console.log('\nStep 2: Add to Doppler');
  console.log('══════════════════════');
  console.log(`Adding SENTRY_DSN to Doppler...`);
  console.log(`Project: ${PROJECT}`);
  console.log(`Config: ${CONFIG}`);
  console.log();

  try {
    await execAsync(
      `doppler secrets set SENTRY_DSN="${dsn}" --project ${PROJECT} --config ${CONFIG}`
    );
    console.log('✅ SENTRY_DSN added to Doppler successfully!\n');
  } catch (error) {
    console.error('❌ Failed to add to Doppler:', error.message);
    console.error('\nYou can add it manually:');
    console.error(`doppler secrets set SENTRY_DSN="${dsn}" --project ${PROJECT} --config ${CONFIG}`);
    process.exit(1);
  }
}

async function updateLocalEnv(rl, dsn) {
  console.log('Step 3: Update Local .env');
  console.log('═════════════════════════');

  const updateLocal = await question(rl, 'Update local .env file with this DSN? (y/n): ');
  if (updateLocal.toLowerCase() !== 'y') return;

  try {
    let envContent = await fs.readFile('.env', 'utf-8');
    envContent = envContent.replace(/SENTRY_DSN=.*/, `SENTRY_DSN=${dsn}`);
    await fs.writeFile('.env', envContent);
    console.log('✅ Local .env file updated!\n');
  } catch (error) {
    console.error('❌ Error updating .env:', error.message);
  }
}

async function testSentryConnection(rl, dsn) {
  console.log('Step 4: Test Connection');
  console.log('═══════════════════════');

  const testNow = await question(rl, 'Test Sentry connection now? (y/n): ');
  if (testNow.toLowerCase() !== 'y') return;

  console.log('\n🧪 Testing Sentry connection...\n');
  const Sentry = await import('@sentry/node');
  Sentry.init({ dsn, environment: 'setup-test', tracesSampleRate: 1.0 });
  const eventId = Sentry.captureMessage('Doppler + Sentry integration test successful!', 'info');
  await Sentry.flush(2000);

  console.log('✅ Test message sent to Sentry!');
  console.log(`   Event ID: ${eventId}`);
  console.log();
  console.log('📊 Check your Sentry dashboard to see the test message');
  console.log('   https://sentry.io/\n');
}

function printCompletion() {
  console.log('╔════════════════════════════════════════════════════════════════╗');
  console.log('║                  Setup Complete! 🎉                           ║');
  console.log('╚════════════════════════════════════════════════════════════════╝');
  console.log();
  console.log('✅ Sentry DSN is now stored in Doppler');
  console.log('✅ Local .env file updated (if you chose to)');
  console.log();
  console.log('Running with Doppler:');
  console.log(`  doppler run --project ${PROJECT} --config ${CONFIG} -- npm start`);
  console.log();
  console.log('Or use local .env:');
  console.log('  npm start');
  console.log();
}

async function setupDopplerSentry() {
  console.log('╔════════════════════════════════════════════════════════════════╗');
  console.log('║        Doppler + Sentry Integration Setup                     ║');
  console.log('╚════════════════════════════════════════════════════════════════╝');
  console.log();

  const rl = readline.createInterface({ input: process.stdin, output: process.stdout });

  try {
    await checkDopplerInstalled();
    await checkDopplerAuthenticated();
    printDsnInstructions();
    const dsn = await promptAndValidateDsn(rl);
    await addDsnToDoppler(dsn);
    await updateLocalEnv(rl, dsn);
    await testSentryConnection(rl, dsn);
    printCompletion();
  } finally {
    rl.close();
  }
}

setupDopplerSentry().catch((error) => {
  console.error('Fatal error:', error);
  process.exit(1);
});#!/usr/bin/env node
/**
 * Sentry Setup Helper
 * Guides you through configuring Sentry for the job management system
 */

import readline from 'readline';
import fs from 'fs/promises';
import path from 'path';

function question(rl, prompt) {
  return new Promise((resolve) => {
    rl.question(prompt, resolve);
  });
}

async function checkSentryAccount(rl) {
  console.log('Step 1: Sentry Account');
  console.log('─────────────────────');
  const hasAccount = await question(rl, 'Do you have a Sentry account? (y/n): ');

  if (hasAccount.toLowerCase() === 'y') return;

  console.log('\n📝 To create a free Sentry account:');
  console.log('   1. Visit: https://sentry.io/signup/');
  console.log('   2. Sign up with your email or GitHub');
  console.log('   3. Create a new project (select Node.js)');
  console.log('   4. Copy your DSN from the project settings');
  console.log();

  const created = await question(rl, 'Have you created an account? (y/n): ');
  if (created.toLowerCase() !== 'y') {
    console.log('\n⏸️  Setup paused. Run this script again when you have your Sentry account.');
    return false;
  }
}

async function promptAndValidateDsn(rl) {
  console.log('\nStep 2: Get Your DSN');
  console.log('────────────────────');
  console.log('Your Sentry DSN looks like:');
  console.log('https://abc123def456@o123456.ingest.sentry.io/7890123');
  console.log();
  console.log('📍 To find your DSN:');
  console.log('   1. Go to https://sentry.io/');
  console.log('   2. Select your project');
  console.log('   3. Go to Settings → Projects → [Your Project] → Client Keys (DSN)');
  console.log('   4. Copy the DSN');
  console.log();

  const dsn = await question(rl, 'Enter your Sentry DSN: ');
  if (!dsn || dsn.trim() === '' || !dsn.includes('sentry.io')) {
    console.log('\n❌ Invalid DSN format. Please run the script again with a valid DSN.');
    return null;
  }
  return dsn.trim();
}

async function updateEnvFile(dsn) {
  console.log('\nStep 3: Updating Configuration');
  console.log('──────────────────────────────');

  const envPath = path.join(process.cwd(), '.env');
  let envContent = await fs.readFile(envPath, 'utf-8');
  envContent = envContent.replace(/SENTRY_DSN=.*/, `SENTRY_DSN=${dsn}`);
  await fs.writeFile(envPath, envContent);
  console.log('✅ .env file updated successfully!');
  console.log();
}

async function testSentryConnection(rl, dsn) {
  console.log('Step 4: Testing Connection');
  console.log('──────────────────────────');

  const test = await question(rl, 'Would you like to test the Sentry connection? (y/n): ');
  if (test.toLowerCase() !== 'y') return;

  console.log('\n🧪 Testing Sentry connection...');
  console.log('   (This will send a test error to Sentry)');
  console.log();

  const Sentry = await import('@sentry/node');
  Sentry.init({ dsn, environment: 'setup-test', tracesSampleRate: 1.0 });
  const eventId = Sentry.captureMessage('Sentry setup test - Configuration successful!', 'info');
  await Sentry.flush(2000);

  console.log('✅ Test message sent!');
  console.log(`   Event ID: ${eventId}`);
  console.log();
  console.log('📊 Check your Sentry dashboard:');
  console.log(`   https://sentry.io/organizations/`);
  console.log();
  console.log('   You should see a message: "Sentry setup test - Configuration successful!"');
}

function printCompletion() {
  console.log();
  console.log('╔════════════════════════════════════════════════════════════════╗');
  console.log('║                    Setup Complete! 🎉                         ║');
  console.log('╚════════════════════════════════════════════════════════════════╝');
  console.log();
  console.log('✅ Sentry is now configured!');
  console.log();
  console.log('Next steps:');
  console.log('  1. All job errors will automatically be logged to Sentry');
  console.log('  2. Performance metrics will be tracked');
  console.log('  3. Set up alerts in Sentry dashboard (recommended)');
  console.log();
  console.log('Useful Sentry features:');
  console.log('  • Real-time error notifications');
  console.log('  • Error grouping and tracking');
  console.log('  • Performance monitoring');
  console.log('  • Release tracking');
  console.log('  • User feedback');
  console.log();
}

async function setupSentry() {
  console.log('╔════════════════════════════════════════════════════════════════╗');
  console.log('║          Sentry Error Monitoring Setup                        ║');
  console.log('╚════════════════════════════════════════════════════════════════╝');
  console.log();

  const rl = readline.createInterface({ input: process.stdin, output: process.stdout });

  try {
    const accountOk = await checkSentryAccount(rl);
    if (accountOk === false) return;

    const dsn = await promptAndValidateDsn(rl);
    if (!dsn) return;

    await updateEnvFile(dsn);
    await testSentryConnection(rl, dsn);
    printCompletion();
  } catch (error) {
    console.error('\n❌ Error updating .env file:', error.message);
    console.error('   Please manually update SENTRY_DSN in .env file');
  } finally {
    rl.close();
  }
}

setupSentry().catch((error) => {
  console.error('Fatal error:', error);
  process.exit(1);
