      "parameters": {
        "repositoryPath": "/path/to/repo"
      },
      "result": {
        "output": "Scan completed successfully",
        "stats": {
          "filesScanned": 42,
          "duplicatesFound": 3,
          "reportGenerated": true
        }
      }
